interface ContentBlock {
  type: 'text' | 'tool_use' | 'tool_result';
  text?: string;
  name?: string;
  input?: unknown;
  content?:
    | string
    | Array<{
        type: string;
        text?: string;
      }>;
}

interface StreamMessage {
  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
  subtype?: string;
  role?: 'assistant' | 'user';
  event?: {
    type: string;
    delta?: {
      type: string;
